176→export const readNotificationService = async (userId, notifId, source) => {
177→    const tableName = source === 'opinion' ? 'notification_opinions' : 'notifications';
178→
179→    const { error } = await supabase
180→        .from(tableName)
181→        .update({ read: true })
182→        .eq('receiver_id', userId)
183→        .eq('id', notifId);
184→
185→    if (error) {
186→        console.error('error updating notification read status:', error);
187→        throw { status: 500, error: 'error updating the notification read status' };
188→    }
189→
190→    return { message: 'notification was read!' };
191→};
