172→        throw new AppError(400, 'journalId is undefined');
173→    }
174→
175→    const {data:checkExisting, error: errorCheckExisting} = await supabase
176→    .from('bookmarks')
177→    .select('*')
178→    .eq('user_id',userId)
179→    .eq('journal_id', journalId)
180→    .maybeSingle()
181→
182→    if(errorCheckExisting){
