213→export const uploadOpinionReplyService = async(parent_id, opinion, user_id) =>{
214→    if(!parent_id || !user_id){
215→        throw new AppError(400, 'parentid or userid is undefined');
216→    }
217→    if(!opinion || typeof opinion !== 'string'){
218→        throw new AppError(400, 'opinion is undefined or opinion is not a string');
219→    }
220→
221→    const {data: parentOpinion, error: errorParentOpinion} = await supabase
222→    .from('opinions')
223→    .select('user_id')
224→    .eq('id', parent_id)
225→    .maybeSingle();
226→
227→    if(errorParentOpinion){
228→        console.error('supabase error while fetching parent opinion', errorParentOpinion.message);
229→        throw new AppError(500, 'supabase error while fetching parent opinion');
230→    }
231→    if(!parentOpinion?.user_id){
232→        throw new AppError(404, 'parent opinion not found');
233→    }
234→
235→    const receiver_id = parentOpinion.user_id;
236→    const isOwner = user_id === receiver_id;
237→
238→    const insertNotifPromise = supabase
239→    .from('notification_opinions')
240→    .insert({type: 'reply', read: false, receiver_id: receiver_id, sender_id: user_id, opinion_id: parent_id})
241→
242→    const insertOpinionReplyPromise = supabase
243→    .from('opinions')
244→    .insert({user_id: user_id, parent_id: parent_id, opinion: opinion})
245→
246→    const [ insertNotif, insertOpinionReply] = await Promise.all([
247→        isOwner ? Promise.resolve({error: null}) : insertNotifPromise, insertOpinionReplyPromise
248→    ])
249→    const {error: errorUploadOpinionReply} = insertOpinionReply;
250→    const {error: errorInsertNotif} = insertNotif;
251→
252→    if(errorUploadOpinionReply || errorInsertNotif) {
253→        console.error('supabase error:', errorInsertNotif?.message || errorUploadOpinionReply?.message);
254→        throw new AppError(500, 'supabase error');
255→    }
256→
257→    // Non-fatal: send @mention notifications
258→    try {
259→        const mentionMatches = opinion.match(/@([\w-]+)/g);
260→        if (mentionMatches && mentionMatches.length > 0) {
261→            const usernames = [...new Set(mentionMatches.map(m => m.slice(1)))].slice(0, 10);
262→            const { data: mentionedUsers } = await supabase
263→                .from('users')
264→                .select('id, username')
265→                .in('username', usernames);
266→            if (mentionedUsers && mentionedUsers.length > 0) {
267→                const notifs = mentionedUsers
268→                    .filter(u => u.id !== user_id && u.id !== receiver_id)
269→                    .map(u => ({
270→                        sender_id: user_id,
271→                        receiver_id: u.id,
272→                        opinion_id: parent_id,
273→                        type: 'mention',
274→                        read: false,
275→                    }));
276→                if (notifs.length > 0) {
277→                    await supabase.from('notification_opinions').insert(notifs);
278→                }
279→            }
280→        }
281→    } catch (mentionErr) {
282→        console.error('non-fatal: opinion reply mention notification error', mentionErr?.message);
283→    }
284→
285→    return {message: 'success'};
