 3→const RANGE_PRESETS = {
 4→    '7d': 7,
 5→    '30d': 30,
 6→    '90d': 90,
 7→};
 8→
 9→function computeDateRange(range) {
10→    const end = new Date();
11→    end.setUTCHours(23, 59, 59, 999);
12→
13→    if (range === 'all') {
14→        // 5 years back as a practical "all time"
15→        const start = new Date();
16→        start.setUTCFullYear(start.getUTCFullYear() - 5);
17→        start.setUTCHours(0, 0, 0, 0);
18→        return { start: start.toISOString(), end: end.toISOString() };
19→    }
20→
21→    const days = RANGE_PRESETS[range];
22→    if (!days) throw new Error('Invalid range. Use 7d, 30d, 90d, or all');
23→
24→    const start = new Date();
25→    start.setUTCDate(start.getUTCDate() - days);
26→    start.setUTCHours(0, 0, 0, 0);
27→
28→    return { start: start.toISOString(), end: end.toISOString() };
29→}
