130→const attachRepostSources = async (journals, { includeContent = false } = {}) => {
131→    const items = Array.isArray(journals) ? journals : [journals];
132→    const sourceIds = [...new Set(
133→        items
134→            .filter(j => j.is_repost === true && j.repost_source_journal_id != null)
135→            .map(j => j.repost_source_journal_id)
136→    )];
137→
138→    if (sourceIds.length === 0) {
139→        items.forEach(j => { j.repost_source = null; });
140→        return journals;
141→    }
142→
143→    const cols = includeContent
144→        ? 'id, title, content, preview_text, thumbnail_url, post_type, created_at, users(id, name, image_url, badge)'
145→        : 'id, title, preview_text, thumbnail_url, post_type, created_at, users(id, name, image_url, badge)';
146→
147→    const { data: sources, error } = await supabase
148→        .from('journals')
149→        .select(cols)
150→        .in('id', sourceIds);
151→
152→    if (error) {
153→        console.error('supabase error fetching repost sources:', error.message);
154→        items.forEach(j => { j.repost_source = null; });
155→        return journals;
156→    }
157→
158→    const sourceMap = new Map(sources.map(s => [s.id, s]));
159→    items.forEach(j => {
160→        j.repost_source = j.repost_source_journal_id
161→            ? (sourceMap.get(j.repost_source_journal_id) || null)
162→            : null;
163→    });
164→
165→    return journals;
166→};
