216→        return res.status(400).json({ error: 'username must start/end with a letter or number and cannot have consecutive hyphens' });
217→    }
218→
219→    const normalized = trimmed.toLowerCase();
220→    if (RESERVED_USERNAMES.has(normalized)) {
221→        return res.status(400).json({ error: 'this username is reserved' });
222→    }
223→
224→    // Check uniqueness
225→    const { data: existing } = await supabase
226→        .from('users')
227→        .select('id')
228→        .ilike('username', normalized)
229→        .neq('id', userId)
230→        .limit(1);
231→
232→    if (existing && existing.length > 0) {
233→        return res.status(409).json({ error: 'username is already taken' });
234→    }
235→
236→    const { error: updateError } = await supabase
237→        .from('users')
238→        .update({ username: normalized })
239→        .eq('id', userId);
240→
241→    if (updateError) {
242→        console.error('update-username error:', updateError.message);
243→        return res.status(500).json({ error: 'failed to update username' });
244→    }
245→
246→    return res.status(200).json({ message: 'success', username: normalized });
247→});
