15→/**
16→ * Generate a single embedding from an array of interest strings.
17→ * Joins them into a comma-separated string and runs through the embedding pipeline.
18→ */
19→export const generateInterestsEmbedding = async (interests) => {
20→    if (!Array.isArray(interests) || interests.length === 0) {
21→        return null;
22→    }
23→
24→    const joined = interests
25→        .filter(i => typeof i === 'string' && i.trim())
26→        .join(', ');
27→
28→    if (!joined) return null;
29→
30→    return GenerateEmbeddings(joined, '');
31→};
